static inline uint32_t CeilDiv(uint32_t a, uint32_t b)
{
    return (a + b - 1u) / b;
}
} // namespace

namespace optiling {

static ge::graphStatus TilingFunc(gert::TilingContext *context)
{
    GemmMultiplyLeakyreluCustomTilingData tiling;

    const gert::Shape* x_shape = context->GetInputShape(0); // [M, K]
    const gert::Shape* w_shape = context->GetInputShape(1); // [K, N] (note: Python binding transposes)
    if (x_shape->GetDimNum() != 2 || w_shape->GetDimNum() != 2) {
        return ge::GRAPH_FAILED;
    }

    const uint32_t M = static_cast<uint32_t>(x_shape->GetDim(0));
    const uint32_t K = static_cast<uint32_t>(x_shape->GetDim(1));
    const uint32_t K_w = static_cast<uint32_t>(w_shape->GetDim(0));
    const uint32_t N = static_cast<uint32_t>(w_shape->GetDim(1));

    if (K != K_w) {
        return ge::GRAPH_FAILED;
    }

    const gert::RuntimeAttrs *attrs = context->GetAttrs();
    const float *multiplier = attrs->GetAttrPointer<float>(0);
    const float *negativeSlope = attrs->GetAttrPointer<float>(1);

    // Simple tiling choices for the post-op vector stage.
    const uint32_t tileN = 128; // vector-friendly width
    const uint32_t tileK = 256; // friendly reduction step for reuse in potential micro-k loops

    uint32_t blockDim = CeilDiv(M, 1u); // at least 1 row per block
    if (blockDim < 8u) blockDim = 8u;
    if (blockDim > 24u) blockDim = 24u;
    context->SetBlockDim(blockDim);

    tiling.set_M(M);
    tiling.set_K(K);
    tiling.set_N(N);
    tiling.set_blockDim(blockDim);
    tiling.set_tileN(tileN);
    tiling.set_tileK(tileK);
    tiling.set_multiplier(*multiplier);
    tiling.set_negativeSlope(*negativeSlope);

    tiling.SaveToBuffer(context->GetRawTilingData()->GetData(),
                        context->GetRawTilingData()->GetCapacity());
    context->GetRawTilingData()->SetDataSize(tiling.GetDataSize());

    size_t *currentWorkspace = context->GetWorkspaceSizes(1);
    currentWorkspace[0] = 0;
    return ge::GRAPH_SUCCESS;
}

} // namespace optiling

namespace ge {
static ge::graphStatus InferShape(gert::InferShapeContext *context)
{
    const gert::Shape *x_shape = context->GetInputShape(0); // [M, K]
    const gert::Shape *w_shape = context->GetInputShape(1); // [K, N]
    if (x_shape->GetDimNum() != 2 || w_shape->GetDimNum() != 2) {
        return GRAPH_FAILED;
    }
    const int64_t M = x_shape->GetDim(0);
    const int64_t N = w_shape->GetDim(1);
    gert::Shape *y_shape = context->GetOutputShape(0);
    y_shape->SetDimNum(2);
    y_shape->SetDim(0, M);
    y_shape->SetDim(1, N);
    return GRAPH_SUCCESS;
}

